import { test as base, request as baseRequest, expect } from '@playwright/test';

type WorkerFixtures = {
  seededItemId: number;
};

export const test = base.extend<{}, WorkerFixtures>({
  seededItemId: [
    async ({}, use) => {
      // Worker-scoped fixtures cannot use page/context, but can use apiRequest
      const context = await baseRequest.newContext({
        baseURL: process.env.BASE_URL ?? 'http://localhost:3000',
      });

      const response = await context.post('/api/items', {
        data: { name: 'Worker Item' },
      });
      expect(response.status()).toBe(201);

      const body = await response.json() as { id: number };
      const itemId = body.id;

      await use(itemId);

      // Teardown: delete the seeded record
      await context.delete(`/api/items/${itemId}`);
      await context.dispose();
    },
    { scope: 'worker' },
  ],
});

