import { Page, Locator } from '@playwright/test';

type ShippingAddress = {
  street: string;
  city: string;
  zip: string;
};

type OrderConfirmation = {
  orderId: string;
  totalAmount: string;
};

interface ICheckoutPage {
  goto(): Promise<void>;
  fillShipping(address: ShippingAddress): Promise<void>;
  placeOrder(): Promise<OrderConfirmation>;
  totalPrice(): Locator;
}

export class CheckoutPage implements ICheckoutPage {
  constructor(private readonly page: Page) {}

  async goto(): Promise<void> {
    await this.page.goto('/checkout');
  }

  async fillShipping(address: ShippingAddress): Promise<void> {
    await this.page.getByLabel('Street').fill(address.street);
    await this.page.getByLabel('City').fill(address.city);
    await this.page.getByLabel('ZIP').fill(address.zip);
  }

  async placeOrder(): Promise<OrderConfirmation> {
    await this.page.getByRole('button', { name: 'Place Order' }).click();
    await this.page.waitForURL(/\/orders\/[\w-]+\/confirmation/);

    const orderId = this.page.url().split('/orders/')[1].split('/')[0];
    const totalAmount = await this.totalPrice().innerText();

    return { orderId, totalAmount };
  }

  totalPrice(): Locator {
    return this.page.getByTestId('order-total');
  }
}

