import { FullConfig } from '@playwright/test';

type SeedResponse = { schemaId: string };

export default async function globalSetup(_config: FullConfig): Promise<void> {
  const adminKey = process.env.ADMIN_API_KEY ?? '';
  const baseURL = process.env.BASE_URL ?? 'http://localhost:3000';

  const response = await fetch(`${baseURL}/api/test-db/seed`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${adminKey}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ reset: true }),
  });

  if (!response.ok) {
    throw new Error(`Seed failed: ${response.status} ${await response.text()}`);
  }

  const { schemaId } = (await response.json()) as SeedResponse;
  process.env.TEST_SCHEMA_ID = schemaId;
  console.log(`[globalSetup] seeded schema: ${schemaId}`);
}

// globalTeardown.ts
export default async function globalTeardown(): Promise<void> {
  const schemaId = process.env.TEST_SCHEMA_ID;
  const adminKey = process.env.ADMIN_API_KEY ?? '';
  const baseURL = process.env.BASE_URL ?? 'http://localhost:3000';

  if (!schemaId) return;

  await fetch(`${baseURL}/api/test-db/${schemaId}`, {
    method: 'DELETE',
    headers: { Authorization: `Bearer ${adminKey}` },
  });

  console.log(`[globalTeardown] deleted schema: ${schemaId}`);
}

