import { test, expect } from '@playwright/test';

test('export job completes and download link appears', async ({ page, request }) => {
  await page.goto('/reports');

  await page.getByRole('button', { name: 'Trigger Export' }).click();

  // Poll the API until the export job is complete
  await expect
    .poll(
      async () => {
        const response = await request.get('/api/exports/latest');
        if (!response.ok()) return null;
        return response.json();
      },
      {
        intervals: [2_000],
        timeout: 30_000,
        message: 'Export job did not complete within 30 seconds',
      }
    )
    .toMatchObject({
      status: 'complete',
      url: expect.stringMatching(/\.csv$/),
    });

  // Now assert the UI reflects the completed export
  await expect(
    page.getByRole('link', { name: /Download Export/ })
  ).toBeVisible();
});

