  const emailError = page.getByTestId('error-email');
  const passwordError = page.getByTestId('error-password');

  await expect.soft(nameError).toBeVisible();
  await expect.soft(nameError).toHaveText('Name is required');

  await expect.soft(emailError).toBeVisible();
  await expect.soft(emailError).toHaveText('Email is required');

  await expect.soft(passwordError).toBeVisible();
  await expect.soft(passwordError).toHaveText('Password must be at least 8 characters');

  // Hard assertion: confirm no navigation away from the signup page
  await expect(page).toHaveURL('/signup');
});
